1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUE: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	const DEDUCTIBLE = 100;
31	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
32	const CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	function calculateItemPremium(item: any): { itemPremium: number; basePremium: number } {
37	  const basePremium = BASE_PREMIUM[item.type] ?? 0;
38	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
39	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
40	  return { itemPremium: basePremium + cursedSurcharge + enchantmentSurcharge, basePremium };
41	}
42	
43	function computePremiumBreakdown(items: any[]): { itemPremiums: number; policyBase: number } {
44	  const componentCounts: Record<string, number> = {};
45	  let itemPremiums = 0;
46	  let policyBase = 0;
47	
48	  for (const item of items) {
49	    if (COMPONENT_TYPES.has(item.type)) {
50	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
51	    } else {
52	      if (!(item.type in BASE_PREMIUM)) {
53	        throw new Error(`Unknown item type: ${item.type}`);
54	      }
55	      const { itemPremium, basePremium } = calculateItemPremium(item);
56	      policyBase += basePremium;
57	      itemPremiums += itemPremium;
58	    }
59	  }
60	
61	  for (const [type, count] of Object.entries(componentCounts)) {
62	    const unitPrice = BASE_PREMIUM[type] ?? 0;
63	    const componentPremium = count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
64	    itemPremiums += componentPremium;
65	    policyBase += count * unitPrice;
66	  }
67	
68	  return { itemPremiums, policyBase };
69	}
