71	function processClaim(
72	  step: any,
73	  policies: Record<number, any[]>,
74	  capRemaining: Record<number, number>,
75	): { payout: number; remainingCap: number } {
76	  const policyItems = policies[step.policy];
77	  const insuranceSum = policyItems.reduce(
78	    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
79	    0,
80	  );
81	  if (!(step.policy in capRemaining)) {
82	    capRemaining[step.policy] = insuranceSum * 2;
83	  }
84	  const damageCounts: Record<string, number> = {};
85	  for (const damage of step.incident.damages) {
86	    if (damage.amount < 0) {
87	      throw new Error(`Negative damage amount: ${damage.amount}`);
88	    }
89	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
90	  }
91	  for (const [type, count] of Object.entries(damageCounts)) {
92	    const policyCount = policyItems.filter((item: any) => item.type === type).length;
93	    if (count > policyCount) {
94	      throw new Error(`More damages of type ${type} than policy covers`);
95	    }
96	  }
97	
98	  let totalPayout = 0;
99	  for (const damage of step.incident.damages) {
100	    const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
101	    if (!policyItem) {
102	      throw new Error(`Item type ${damage.itemType} not in policy`);
103	    }
104	    const reimbursement = policyItem.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD ? damage.amount * CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE : damage.amount;
105	    const payout = reimbursement - DEDUCTIBLE;
106	    totalPayout += Math.max(0, payout);
107	  }
108	  totalPayout = Math.min(totalPayout, capRemaining[step.policy]);
109	  totalPayout = Math.floor(totalPayout);
110	  capRemaining[step.policy] -= totalPayout;
111	  return { payout: totalPayout, remainingCap: capRemaining[step.policy] };
112	}
113	
114	function processQuote(
115	  step: any,
116	  index: number,
117	  yearsWithMHPCO: number,
118	): { premium: number } {
119	  const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
120	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
121	  const loyaltyDiscount =
122	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
123	      ? policyBase * LOYALTY_DISCOUNT_RATE
124	      : 0;
125	  const followUpDiscount =
126	    index > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
127	  const premium =
128	    Math.ceil(
129	      itemPremiums +
130	        firstInsuranceSurcharge -
131	        loyaltyDiscount -
132	        followUpDiscount,
133	    ) + PROCESSING_FEE;
134	  return { premium };
135	}
136	
137	export function processScenario(scenario: any): unknown {
138	  const policies: Record<number, any[]> = {};
139	  const capRemaining: Record<number, number> = {};
140	
141	  const results = scenario.steps.map((step: any, index: number) => {
142	    if (step.op === "claim") {
143	      return processClaim(step, policies, capRemaining);
144	    }
145	    policies[index] = step.items;
146	    return processQuote(step, index, scenario.customer.yearsWithMHPCO);
147	  });
148	  return { results };
149	}
